template:
pub enum TrafficLight {
    Red,
    Yellow,
    Green,
}

/// Returns how many seconds to wait at the given traffic light.
pub fn wait_time(light: TrafficLight) -> u32 {
    match light {
        [[SLOT red_arm]]
        [[SLOT yellow_arm]]
        [[SLOT green_arm]]
    }
}

fn main() {
    println!("Red: {} seconds", wait_time(TrafficLight::Red));
    println!("Yellow: {} seconds", wait_time(TrafficLight::Yellow));
    println!("Green: {} seconds", wait_time(TrafficLight::Green));
}
